"""Audit — cross-reference manifest against filesystem (read-only).

Public API:
    AuditResult  – dataclass with missing/stale/untracked lists
    run_audit()  – main entry point; returns AuditResult
"""

from __future__ import annotations

from dataclasses import dataclass, field
from pathlib import Path

from model_shelf.manifest import _sha256_dir_for_rebuild, load_manifest
from model_shelf.import_model import _sha256_file
from model_shelf.resolver import (
    SUPPORTED_FORMATS,
    Config,
    check_storage_available,
)


@dataclass
class AuditResult:
    """Result of a shelf audit."""

    missing: list[str] = field(default_factory=list)
    untracked: list[str] = field(default_factory=list)
    stale: list[str] = field(default_factory=list)

    def to_dict(self) -> dict:
        return {
            "missing": list(self.missing),
            "untracked": list(self.untracked),
            "stale": list(self.stale),
        }


def _build_manifest_tracked_set(
    shelf_root: Path, models: dict
) -> set[str]:
    """Build a set of absolute str paths for every file listed in the manifest."""
    tracked: set[str] = set()
    for entry in models.values():
        fmt = entry.get("format", "")
        if fmt not in SUPPORTED_FORMATS:
            continue
        repo_id = entry.get("repo_id", "")
        if "/" not in repo_id:
            continue
        publisher, _, repo_name = repo_id.partition("/")
        model_dir = shelf_root / fmt / publisher / repo_name
        for fname in entry.get("files", []):
            tracked.add(str(model_dir / fname))
    return tracked


def _should_skip_file(path: Path) -> bool:
    """Return True if the path should be excluded from the untracked scan."""
    if path.name.startswith("._"):
        return True
    if ".cache" in path.parts:
        return True
    return False


def run_audit(config: Config) -> AuditResult:
    """Cross-reference manifest entries against the filesystem.

    Returns AuditResult with:
      - missing:  repo_ids whose tracked files don't exist on disk
      - stale:    repo_ids whose SHA256 no longer matches the filesystem
      - untracked: filesystem paths (absolute str) not tracked in manifest
    """
    check_storage_available(config)
    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    # Build the set of all manifest-tracked absolute paths
    tracked_paths = _build_manifest_tracked_set(shelf_root, models)

    # --- Missing + Stale checks ---
    missing: list[str] = []
    stale: list[str] = []

    for repo_id, entry in models.items():
        fmt = entry.get("format", "")
        if fmt not in SUPPORTED_FORMATS:
            continue
        if "/" not in repo_id:
            continue
        publisher, _, repo_name = repo_id.partition("/")
        model_dir = shelf_root / fmt / publisher / repo_name

        # Check that every tracked file exists
        all_exist = True
        for fname in entry.get("files", []):
            fp = model_dir / fname
            if not fp.is_file():
                all_exist = False
                break

        if not all_exist:
            missing.append(repo_id)
            continue  # Don't bother with stale check if files are missing

        # SHA256 check
        entry_sha = entry.get("sha256", "")
        if fmt == "gguf":
            # Single-file GGUF: use _sha256_file
            gguf_files = entry.get("files", [])
            if gguf_files:
                fp = model_dir / gguf_files[0]
                try:
                    current_sha = _sha256_file(fp)
                except OSError:
                    missing.append(repo_id)
                    continue
                if current_sha != entry_sha:
                    stale.append(repo_id)
        else:
            # MLX / safetensors: use _sha256_dir_for_rebuild (same exclusion logic
            # that rebuild_manifest uses, so audit won't flag expected differences)
            if model_dir.is_dir():
                try:
                    current_sha = _sha256_dir_for_rebuild(model_dir)
                except OSError:
                    missing.append(repo_id)
                    continue
                if current_sha != entry_sha:
                    stale.append(repo_id)
            else:
                missing.append(repo_id)

    # --- Untracked check ---
    untracked: list[str] = []
    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue
        for f in fmt_dir.rglob("*"):
            if not f.is_file():
                continue
            if _should_skip_file(f):
                continue
            f_str = str(f)
            if f_str not in tracked_paths:
                untracked.append(f_str)

    return AuditResult(
        missing=sorted(missing),
        untracked=sorted(untracked),
        stale=sorted(stale),
    )

