    shelf_root = config.shelf_root

    manifest = load_manifest(shelf_root)
    models = manifest.get("models", {})

    tracked_set = _build_tracked_set(shelf_root, models)

    incomplete: list[str] = []
    orphaned: list[str] = []
    empty_dirs: list[str] = []
    reclaimable_bytes: int = 0
    scanned_dirs: set[str] = set()

    for fmt in SUPPORTED_FORMATS:
        fmt_dir = shelf_root / fmt
        if not fmt_dir.is_dir():
            continue

        for publisher in sorted(fmt_dir.iterdir()):
            if not publisher.is_dir():
                continue
            if _should_skip_path(publisher):
                continue

            for repo in sorted(publisher.iterdir()):
                if not repo.is_dir():
                    continue
                if _should_skip_path(repo):
                    continue

                repo_str = str(repo)
                scanned_dirs.add(repo_str)

                # -- Incomplete download detection --
                if fmt == "gguf":
                    gguf_files = list(repo.glob("*.gguf"))
                    gguf_files = [f for f in gguf_files if not _should_skip_path(f)]
                    if not gguf_files:
                        incomplete.append(repo_str)
                else:
                    # MLX / safetensors
                    config_json = repo / "config.json"
                    if not config_json.is_file():
                        incomplete.append(repo_str)
                    elif fmt == "safetensors":
                        safetensor_files = [
                            f for f in repo.glob("*.safetensors")
                            if not _should_skip_path(f)
                        ]
                        if not safetensor_files:
                            incomplete.append(repo_str)

                # -- Scan for orphans inside repo dirs --
                for f in sorted(repo.rglob("*")):
                    if not f.is_file():
                        continue
                    if _should_skip_path(f):
                        continue
                    f_str = str(f)
                    if f_str not in tracked_set:
                        orphaned.append(f_str)
                        try:
                            reclaimable_bytes += f.stat().st_size
                        except OSError:
                            pass

            # Also scan for loose orphaned files at the publisher level
            for f in sorted(publisher.rglob("*")):
                if not f.is_file():
                    continue
                if _should_skip_path(f):
                    continue
                # Skip files inside repo dirs (already scanned above)
                parent_str = str(f.parent)
                if parent_str in scanned_dirs:
                    continue
                f_str = str(f)
                if f_str not in tracked_set:
                    orphaned.append(f_str)
                    try:
                        reclaimable_bytes += f.stat().st_size
                    except OSError:
                        pass

        # -- Empty directory detection (bottom-up: deepest first) --
        all_dirs = sorted(
            (d for d in fmt_dir.rglob("*") if d.is_dir()),
            key=lambda d: -len(d.parts),  # deepest first
        )
        for d in all_dirs:
            if _should_skip_path(d):
                continue
            try:
                contents = [c for c in d.iterdir()
                            if not _should_skip_path(c)]
            except OSError:
                continue
            if not contents:
                empty_dirs.append(str(d))

    return GCResult(
        incomplete_downloads=sorted(incomplete),
        orphaned_files=sorted(orphaned),
        empty_dirs=sorted(empty_dirs),
        total_reclaimable_bytes=reclaimable_bytes,
    )

